package com.hospital.management.service.impl;
import com.hospital.management.dao.*;import com.hospital.management.dao.impl.*;import com.hospital.management.model.*;import com.hospital.management.service.*;import com.hospital.management.util.*;import com.hospital.management.validation.*;import org.slf4j.*;import java.sql.*;import java.time.*;import java.util.*;
/** Appointment use cases with role ownership, transactions, conflicts, state transitions and safe auditing. */
public class AppointmentServiceImpl implements AppointmentService {private static final Logger LOG=LoggerFactory.getLogger(AppointmentServiceImpl.class);private final AppointmentDao appointments;private final AppointmentAvailabilityService availability;private final PatientDao patients;private final DoctorDao doctors;private final AppointmentValidator validator;private final AuditLogDao audit;
public AppointmentServiceImpl(){this(new AppointmentDaoImpl(),new AppointmentAvailabilityServiceImpl(),new PatientDaoImpl(),new DoctorDaoImpl(),new AppointmentValidator(),new AuditLogDaoImpl());}public AppointmentServiceImpl(AppointmentDao a,AppointmentAvailabilityService av,PatientDao p,DoctorDao d,AppointmentValidator v,AuditLogDao l){appointments=a;availability=av;patients=p;doctors=d;validator=v;audit=l;}
public Page<Appointment> listAppointments(PageRequest p,Long pi,Long di,Long dep,LocalDate f,LocalDate t,String st,AuthenticatedUser u){PageRequest q=p==null?new PageRequest(1,10,""):p;try{if(u==null)return empty(q);if("DOCTOR".equals(u.getRoleName())){Doctor d=doctorFor(u);if(d==null)return empty(q);di=d.getDoctorId();}else if("PATIENT".equals(u.getRoleName())){Patient x=patientFor(u);if(x==null)return empty(q);pi=x.getPatientId();}else if(!staff(u))return empty(q);return appointments.findAll(q,pi,di,dep,f,t,st);}catch(Exception e){LOG.error("Appointment listing failed",e);return empty(q);}}
public Optional<Appointment> getAppointment(Long id,AuthenticatedUser u){try{return appointments.findById(id).filter(a->canView(a,u));}catch(SQLException e){LOG.error("Appointment lookup failed",e);return Optional.empty();}}
public List<AvailableSlot> getAvailableSlots(Long doctorId,LocalDate date,Long exclude,AuthenticatedUser u){if(u==null||!Set.of("ADMIN","RECEPTIONIST","PATIENT").contains(u.getRoleName()))return List.of();return availability.getAvailableSlots(doctorId,date,exclude);}
public ServiceResult<Long> createAppointment(AppointmentForm f,AuditContext x,AuthenticatedUser u){ValidationResult v=validator.validateBooking(f);if(v.hasErrors())return failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v);try{if(u==null||!Set.of("ADMIN","RECEPTIONIST","PATIENT").contains(u.getRoleName()))return deniedL(null,x);if("PATIENT".equals(u.getRoleName())){Patient own=patientFor(u);if(own==null||!own.getPatientId().equals(f.getPatientId()))return deniedL(null,x);}Patient p=patients.findById(f.getPatientId()).orElse(null);Doctor d=doctors.findById(f.getDoctorId()).orElse(null);if(p==null)return failL(ServiceResult.Status.NOT_FOUND,"Patient not found");if(!"ACTIVE".equals(p.getStatus()))return failL(ServiceResult.Status.CONFLICT,"Patient must be active");if(d==null)return failL(ServiceResult.Status.NOT_FOUND,"Doctor not found");if(!"ACTIVE".equals(d.getStatus())||!"ACTIVE".equals(d.getUserStatus()))return failL(ServiceResult.Status.CONFLICT,"Doctor account must be active");LocalDate date=LocalDate.parse(f.getAppointmentDate());LocalTime start=LocalTime.parse(f.getStartTime());AvailableSlot slot=availability.getAvailableSlots(d.getDoctorId(),date,null).stream().filter(s->s.getStartTime().equals(start)).findFirst().orElse(null);if(slot==null){event("APPOINTMENT_BOOKING_BLOCKED",null,x);return failL(ServiceResult.Status.CONFLICT,"Selected slot is no longer available");}if(appointments.existsDoctorBooking(d.getDoctorId(),date,start,null)||appointments.existsPatientOverlap(p.getPatientId(),date,start,slot.getEndTime(),null)){event("APPOINTMENT_BOOKING_BLOCKED",null,x);return failL(ServiceResult.Status.CONFLICT,"Appointment conflicts with an existing booking");}Appointment a=from(f,p.getPatientId(),d.getDoctorId(),date,slot.getStartTime(),slot.getEndTime(),u.getUserId());long id=transaction(c->appointments.create(c,a));event("APPOINTMENT_CREATED",id,x);return ServiceResult.success("Appointment created",id);}catch(SQLException e){LOG.error("Appointment creation failed",e);if(SqlExceptionUtil.isUniqueConstraintViolation(e))return failL(ServiceResult.Status.CONFLICT,"Selected slot is no longer available");return failL(ServiceResult.Status.SYSTEM_ERROR,"Appointment service is temporarily unavailable");}catch(RuntimeException e){LOG.error("Appointment creation failed",e);return failL(ServiceResult.Status.SYSTEM_ERROR,"Appointment service is temporarily unavailable");}}
public ServiceResult<Void> updateAppointment(AppointmentForm f,AuditContext x,AuthenticatedUser u){ValidationResult v=validator.validateDetails(f);if(v.hasErrors())return failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v);try{Appointment a=appointments.findById(f.getAppointmentId()).orElse(null);if(a==null)return fail(ServiceResult.Status.NOT_FOUND,"Appointment not found");if(!canEdit(a,u)){event("APPOINTMENT_ACCESS_DENIED",a.getAppointmentId(),x);return fail(ServiceResult.Status.FORBIDDEN,"Appointment access denied");}if(!blocking(a))return fail(ServiceResult.Status.CONFLICT,"Appointment can no longer be edited");a.setReason(trim(f.getReason()));a.setNotes(trim(f.getNotes()));transaction(c->{appointments.updateDetails(c,a);return null;});event("APPOINTMENT_UPDATED",a.getAppointmentId(),x);return ServiceResult.success("Appointment updated",null);}catch(SQLException e){LOG.error("Appointment update failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Appointment service is temporarily unavailable");}}
public ServiceResult<Void> rescheduleAppointment(AppointmentForm f,AuditContext x,AuthenticatedUser u){ValidationResult v=validator.validateReschedule(f);if(v.hasErrors())return failure(ServiceResult.Status.VALIDATION_ERROR,"Correct the highlighted fields",v);try{Appointment a=appointments.findById(f.getAppointmentId()).orElse(null);if(a==null)return fail(ServiceResult.Status.NOT_FOUND,"Appointment not found");if(!canReschedule(a,u)){event("APPOINTMENT_ACCESS_DENIED",a.getAppointmentId(),x);return fail(ServiceResult.Status.FORBIDDEN,"Appointment access denied");}if(!blocking(a))return fail(ServiceResult.Status.CONFLICT,"Appointment can no longer be rescheduled");LocalDate date=LocalDate.parse(f.getAppointmentDate());LocalTime start=LocalTime.parse(f.getStartTime());AvailableSlot slot=availability.getAvailableSlots(a.getDoctorId(),date,a.getAppointmentId()).stream().filter(s->s.getStartTime().equals(start)).findFirst().orElse(null);if(slot==null)return fail(ServiceResult.Status.CONFLICT,"Selected slot is no longer available");if(appointments.existsDoctorBooking(a.getDoctorId(),date,start,a.getAppointmentId())||appointments.existsPatientOverlap(a.getPatientId(),date,start,slot.getEndTime(),a.getAppointmentId()))return fail(ServiceResult.Status.CONFLICT,"Appointment conflicts with an existing booking");transaction(c->{appointments.reschedule(c,a.getAppointmentId(),date,start,slot.getEndTime(),trim(f.getReason()),trim(f.getNotes()));return null;});event("APPOINTMENT_RESCHEDULED",a.getAppointmentId(),x);return ServiceResult.success("Appointment rescheduled",null);}catch(SQLException e){LOG.error("Appointment reschedule failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Appointment service is temporarily unavailable");}}
public ServiceResult<Void> updateAppointmentStatus(Long id,String action,AuditContext x,AuthenticatedUser u){try{Appointment a=appointments.findById(id).orElse(null);if(a==null)return fail(ServiceResult.Status.NOT_FOUND,"Appointment not found");Optional<String>target=AppointmentStatusTransition.target(a.getStatus(),action);if(target.isEmpty()){event("APPOINTMENT_STATUS_CHANGE_BLOCKED",id,x);return fail(ServiceResult.Status.CONFLICT,"Invalid appointment status transition");}if(!canStatus(a,action,u)){event("APPOINTMENT_ACCESS_DENIED",id,x);return fail(ServiceResult.Status.FORBIDDEN,"Appointment access denied");}transaction(c->{appointments.updateStatus(c,id,target.get());return null;});event("APPOINTMENT_"+("no_show".equals(action)?"NO_SHOW":target.get()),id,x);return ServiceResult.success("Appointment status updated",null);}catch(SQLException e){LOG.error("Appointment status update failed",e);return fail(ServiceResult.Status.SYSTEM_ERROR,"Appointment service is temporarily unavailable");}}
private boolean staff(AuthenticatedUser u){return Set.of("ADMIN","RECEPTIONIST").contains(u.getRoleName());}private boolean canView(Appointment a,AuthenticatedUser u){if(u==null)return false;if(staff(u))return true;if("DOCTOR".equals(u.getRoleName())){Doctor d=doctorFor(u);return d!=null&&d.getDoctorId().equals(a.getDoctorId());}if("PATIENT".equals(u.getRoleName())){Patient p=patientFor(u);return p!=null&&p.getPatientId().equals(a.getPatientId());}return false;}private boolean canEdit(Appointment a,AuthenticatedUser u){return canView(a,u)&&u!=null&&Set.of("ADMIN","RECEPTIONIST","DOCTOR").contains(u.getRoleName());}private boolean canReschedule(Appointment a,AuthenticatedUser u){return canView(a,u)&&u!=null&&Set.of("ADMIN","RECEPTIONIST","PATIENT").contains(u.getRoleName());}private boolean canStatus(Appointment a,String action,AuthenticatedUser u){if(!canView(a,u))return false;if("ADMIN".equals(u.getRoleName()))return true;if("RECEPTIONIST".equals(u.getRoleName()))return Set.of("confirm","cancel").contains(action);if("DOCTOR".equals(u.getRoleName()))return Set.of("confirm","complete","cancel","no_show").contains(action);return "PATIENT".equals(u.getRoleName())&&"cancel".equals(action);}
private Patient patientFor(AuthenticatedUser u){try{return patients.findAll(new PageRequest(1,100,u.getUsername()),"ACTIVE").getContent().stream().filter(p->u.getUserId().equals(p.getUserId())).findFirst().orElse(null);}catch(SQLException e){return null;}}private Doctor doctorFor(AuthenticatedUser u){try{return doctors.findByUserId(u.getUserId()).orElse(null);}catch(SQLException e){return null;}}private Appointment from(AppointmentForm f,Long p,Long d,LocalDate day,LocalTime s,LocalTime e,Long by){Appointment a=new Appointment();a.setPatientId(p);a.setDoctorId(d);a.setAppointmentDate(day);a.setStartTime(s);a.setEndTime(e);a.setReason(trim(f.getReason()));a.setNotes(trim(f.getNotes()));a.setStatus("SCHEDULED");a.setCreatedBy(by);return a;}private boolean blocking(Appointment a){return Set.of("SCHEDULED","CONFIRMED").contains(a.getStatus());}private String trim(String s){return s==null?null:s.trim();}private<T>T transaction(SqlWork<T>w)throws SQLException{try(Connection c=DatabaseConnectionManager.getConnection()){boolean old=c.getAutoCommit();c.setAutoCommit(false);try{T v=w.run(c);c.commit();return v;}catch(SQLException|RuntimeException e){c.rollback();throw e;}finally{c.setAutoCommit(old);}}}private interface SqlWork<T>{T run(Connection c)throws SQLException;}
private void event(String action,Long id,AuditContext x){try{AuditContext a=x==null?new AuditContext(null,null,null):x;audit.recordEvent(action,a.userId(),"APPOINTMENT",id,a.ipAddress(),a.userAgent());}catch(RuntimeException e){LOG.warn("Appointment audit failed: {}",action,e);}}private Page<Appointment>empty(PageRequest p){return new Page<>(List.of(),p.getPageNumber(),p.getPageSize(),0);}private<T>ServiceResult<T>failure(ServiceResult.Status s,String m,ValidationResult v){return ServiceResult.failure(s,m,v.getErrors());}private ServiceResult<Void>fail(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>failL(ServiceResult.Status s,String m){return ServiceResult.failure(s,m,Map.of());}private ServiceResult<Long>deniedL(Long id,AuditContext x){event("APPOINTMENT_ACCESS_DENIED",id,x);return failL(ServiceResult.Status.FORBIDDEN,"Appointment access denied");}}
